    metaDescription: 'Flusspferd Uganda: Kazinga Channel, Murchison Falls Bootsfahrt, Lake Mburo. Verhalten, Population und die 5 besten Beobachtungsorte fuer Nilpferde 2026.',
    breadcrumbs: [{ label: 'Tiere', href: '/#tiere' }, { label: 'Flusspferd' }],
    photoFilter: 'nilpferd',
